export async function generateStaticParams() {
  const posts: Post[] = await fetch(
    'https://jsonplaceholder.typicode.com/posts',
  ).then((res) => res.json());

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
