/**
 * generateMetadata — replaces next/head for dynamic SEO tags.
 */
export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { id } = await params;
  const post: Post = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}`,
  ).then((res) => res.json());

  return {
    title: `${post.title} - My Blog`,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

/**
 * ISR page — equivalent of getStaticProps with revalidate: 300 + fallback: 'blocking'.
 */
export default async function BlogPost({ params }: Props) {
  const { id } = await params;

  try {
    const [post, comments]: [Post, Comment[]] = await Promise.all([
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
        next: { revalidate: 300 },
      }).then((res) => res.json()),
      fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
        next: { revalidate: 300 },
      }).then((res) => res.json()),
    ]);

    return (
      <article>
        <Link href="/blog">&larr; Back</Link>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map((comment) => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    );
  } catch {
    notFound();
  }
}

